function cosine(a, b) {
  let dot = 0, na = 0, nb = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i]; na += a[i] ** 2; nb += b[i] ** 2;
  }
  return dot / (Math.sqrt(na) * Math.sqrt(nb));
}

async function retrieve(question, k = 2) {
  const q = await client.embeddings.create({
    model: "text-embedding-3-small", input: question,
  });
  const qVec = q.data[0].embedding;
  return DOCS.map((doc, i) => ({ doc, score: cosine(qVec, docVectors[i]) }))
    .sort((a, b) => b.score - a.score)
    .slice(0, k);
}

for (const { doc, score } of await retrieve("How long do I have to return something?"))
  console.log(score.toFixed(3), doc);

