function chunkFixed(text, size = 300, overlap = 50) {
  const chunks = [];
  for (let start = 0; start < text.length; start += size - overlap) {
    const end = Math.min(start + size, text.length);
    chunks.push({ start, end, text: text.slice(start, end) });
  }
  return chunks;
}

