function rerank(question, candidates, finalK = 2) {
  const qWords = new Set(question.toLowerCase().replace("?", "").split(" "));
  const overlap = (i) =>
    CORPUS[i].text.toLowerCase().split(" ")
      .filter((w) => qWords.has(w)).length;
  // sort by keyword overlap first, vector score as tiebreaker
  return [...candidates]
    .sort((a, b) => overlap(b.i) - overlap(a.i) || b.score - a.score)
    .slice(0, finalK);
}

