// ingest.mjs (part 1)
import { readFileSync, readdirSync } from "node:fs";

export function chunk(text, size = 500, overlap = 100) {
  const out = [];
  for (let start = 0; start < text.length; start += size - overlap)
    out.push(text.slice(start, start + size));
  return out;
}

export function loadChunks(folder = "docs") {
  const records = [];
  for (const file of readdirSync(folder).filter((f) => f.endsWith(".txt"))) {
    const text = readFileSync(`${folder}/${file}`, "utf8");
    chunk(text).forEach((c, i) =>
      records.push({ id: `${file}-${i}`, text: c,
                     meta: { source: file, chunk: i } }));
  }
  return records;
}

console.log(`${loadChunks().length} chunks loaded`);

